settings.custom_liquid:
{%- comment -%}
Stars + rating + subtext (matches screenshot).
Edit the variables below to change the numbers/text.
{%- endcomment -%}

{%- assign rating_value = 5 -%}
{%- assign rating_max = 5 -%}
{%- assign rating_text = '5/5' -%}
{%- assign subtext = 'Trusted by 5,000+ customers' -%}

{%- style -%}
  .nuve-rating-wrap{
    display: inline-flex;
    flex-direction: column;
    gap: 6px;
  }
  .nuve-rating-top{
    display: inline-flex;
    align-items: center;
    gap: 8px;
  }
  .nuve-stars{
    display: inline-flex;
    gap: 4px;
    line-height: 1;
  }
  .nuve-star{
    width: 16px;
    height: 16px;
    display: inline-block;
  }
  .nuve-star svg{
    width: 100%;
    height: 100%;
    display: block;
    fill: #F5A623; /* warm gold like screenshot */
  }
  .nuve-rating-text{
    font-size: 14px;
    font-weight: 700;
    color: #111;
    line-height: 1;
  }
  .nuve-rating-subtext{
    font-size: 13px;
    font-weight: 500;
    color: #111;
    line-height: 1.2;
  }
{%- endstyle -%}

<div class="nuve-rating-wrap" aria-label="Rated {{ rating_text }}">
  <div class="nuve-rating-top">
    <div class="nuve-stars" role="img" aria-label="{{ rating_value }} out of {{ rating_max }} stars">
      {%- for i in (1..rating_max) -%}
        <span class="nuve-star">
          <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
            <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/>
          </svg>
        </span>
      {%- endfor -%}
    </div>

    <span class="nuve-rating-text">{{ rating_text }}</span>
  </div>

  <div class="nuve-rating-subtext">{{ subtext }}</div>
</div>

{%- comment -%}
Limited Launch Offer pill label (matches screenshot style).
Optional: control visibility via product tag or metafield (see below).
{%- endcomment -%}

{%- assign label_text = 'Limited Launch Offer' -%}

{%- style -%}
  .nuve-launch-offer-badge{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: #000;
    color: #fff;
    font-size: 12px;
    font-weight: 700;
    line-height: 1;
    padding: 7px 14px;
    border-radius: 9999px;
    letter-spacing: 0.2px;
    -webkit-font-smoothing: antialiased;
    text-rendering: geometricPrecision;
  }
{%- endstyle -%}

<span class="nuve-launch-offer-badge">{{ label_text }}</span>

{%- comment -%}
Trust elements row (matches screenshot).
Edit text in the variables below.
{%- endcomment -%}

{%- assign headline = '30-Day Money-Back Guarantee' -%}
{%- assign item_left = 'Secure Checkout' -%}
{%- assign item_right = 'Free Shipping' -%}

{%- style -%}
  .nuve-trust{
    display: flex;
    flex-direction: column;
    gap: 10px;
    color: #111;
  }

  .nuve-trust-line{
    display: inline-flex;
    align-items: center;
    gap: 8px;
    font-size: 14px;
    font-weight: 700;
    line-height: 1.2;
  }

  .nuve-trust-line--sub{
    font-weight: 600;
    font-size: 13px;
    gap: 18px;
  }

  .nuve-trust-item{
    display: inline-flex;
    align-items: center;
    gap: 8px;
    white-space: nowrap;
  }

  .nuve-icon{
    width: 18px;
    height: 18px;
    display: inline-block;
  }

  .nuve-icon svg{
    width: 100%;
    height: 100%;
    display: block;
  }

  .nuve-icon--green svg{
    stroke: #16a34a; /* green */
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-icon--black svg{
    stroke: #111;
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }
{%- endstyle -%}

<div class="nuve-trust">
  <!-- Top line -->
  <div class="nuve-trust-line">
    <span class="nuve-icon nuve-icon--green" aria-hidden="true">
      <!-- Shield check -->
      <svg viewBox="0 0 24 24">
        <path d="M12 2l8 4v6c0 5-3.5 9.4-8 10-4.5-.6-8-5-8-10V6l8-4z"/>
        <path d="M8.5 12.3l2.2 2.2 4.8-5.2"/>
      </svg>
    </span>
    <span>{{ headline }}</span>
  </div>

  <!-- Bottom line -->
  <div class="nuve-trust-line nuve-trust-line--sub">
    <span class="nuve-trust-item">
      <span class="nuve-icon nuve-icon--black" aria-hidden="true">
        <!-- Lock -->
        <svg viewBox="0 0 24 24">
          <path d="M7 11V8a5 5 0 0 1 10 0v3"/>
          <path d="M6 11h12v10H6z"/>
        </svg>
      </span>
      <span>{{ item_left }}</span>
    </span>

    <span class="nuve-trust-item">
      <span class="nuve-icon nuve-icon--black" aria-hidden="true">
        <!-- Shipping / box -->
        <svg viewBox="0 0 24 24">
          <path d="M3 7l9-4 9 4-9 4-9-4z"/>
          <path d="M3 7v10l9 4 9-4V7"/>
          <path d="M12 11v10"/>
        </svg>
      </span>
      <span>{{ item_right }}</span>
    </span>
  </div>
</div>

{%- comment -%}
Premium "Best Results Tips" card
Edit title + tips below.
{%- endcomment -%}

{%- assign title = 'Best Results Tips' -%}
{%- assign kicker = 'Recommended routine' -%}
{%- assign tips = 'Use 2–3x per week, on clean/dry scalp|Always start with the lowest setting|Pair with your favorite growth serum or oil|Take before photos to track your progress!' -%}

{%- style -%}
  .nuve-tips-wrap{
    --ink: #0f172a;
    --muted: rgba(15, 23, 42, 0.72);
    --brand: #557170;
    --cream: #F1EFE7;
    --lilac: #C9B7FF;

    border-radius: 18px;
    padding: 22px 22px;
    background:
      radial-gradient(900px 260px at 15% 0%, rgba(201, 183, 255, 0.20), transparent 55%),
      radial-gradient(900px 260px at 85% 100%, rgba(85, 113, 112, 0.16), transparent 55%),
      linear-gradient(180deg, #ffffff, var(--cream));
    border: 1px solid rgba(15, 23, 42, 0.08);
    box-shadow: 0 14px 40px rgba(15, 23, 42, 0.08);
    overflow: hidden;
  }

  .nuve-tips-header{
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
  }

  .nuve-tips-icon{
    width: 42px;
    height: 42px;
    border-radius: 14px;
    background: rgba(85, 113, 112, 0.10);
    border: 1px solid rgba(85, 113, 112, 0.18);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
  }
  .nuve-tips-icon svg{
    width: 22px;
    height: 22px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tips-kicker{
    display: inline-flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    font-weight: 700;
    color: var(--brand);
    margin-bottom: 6px;
  }
  .nuve-tips-pill{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 10px;
    border-radius: 9999px;
    background: rgba(201, 183, 255, 0.18);
    border: 1px solid rgba(201, 183, 255, 0.35);
    color: var(--ink);
    font-size: 11px;
    font-weight: 700;
    line-height: 1;
  }

  .nuve-tips-title{
    font-size: 22px;
    font-weight: 800;
    color: var(--ink);
    line-height: 1.15;
    margin: 0;
  }

  .nuve-tips-grid{
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    margin-top: 14px;
  }

  .nuve-tip{
    display: grid;
    grid-template-columns: 26px 1fr;
    gap: 12px;
    align-items: flex-start;
    padding: 12px 12px;
    border-radius: 14px;
    background: rgba(255, 255, 255, 0.62);
    border: 1px solid rgba(15, 23, 42, 0.06);
    transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease;
  }

  .nuve-tip:hover{
    transform: translateY(-1px);
    box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);
    background: rgba(255, 255, 255, 0.78);
  }

  .nuve-check{
    width: 22px;
    height: 22px;
    border-radius: 9999px;
    background: rgba(85, 113, 112, 0.12);
    border: 1px solid rgba(85, 113, 112, 0.20);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 2px;
  }
  .nuve-check svg{
    width: 14px;
    height: 14px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2.5;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tip-text{
    font-size: 14px;
    font-weight: 600;
    color: var(--ink);
    line-height: 1.35;
  }

  /* Optional: 2-column on larger screens */
  @media (min-width: 750px){
    .nuve-tips-wrap{ padding: 26px 26px; }
    .nuve-tips-grid{ grid-template-columns: 1fr 1fr; }
    .nuve-tips-title{ font-size: 24px; }
  }
{%- endstyle -%}

<div class="nuve-tips-wrap">
  <div class="nuve-tips-header">
    <div class="nuve-tips-icon" aria-hidden="true">
      <!-- sparkle/idea icon -->
      <svg viewBox="0 0 24 24">
        <path d="M12 2l1.2 3.8L17 7l-3.8 1.2L12 12l-1.2-3.8L7 7l3.8-1.2L12 2z"/>
        <path d="M5 13l.8 2.6L8 16l-2.2.7L5 19l-.8-2.3L2 16l2.2-.4L5 13z"/>
        <path d="M18 13l.8 2.6L21 16l-2.2.7L18 19l-.8-2.3L15 16l2.2-.4L18 13z"/>
      </svg>
    </div>

    <div>
      <div class="nuve-tips-kicker">
        <span class="nuve-tips-pill">{{ kicker }}</span>
      </div>
      <h3 class="nuve-tips-title">{{ title }}</h3>
    </div>
  </div>

  <div class="nuve-tips-grid" role="list">
    {%- assign tip_items = tips | split: '|' -%}
    {%- for t in tip_items -%}
      <div class="nuve-tip" role="listitem">
        <span class="nuve-check" aria-hidden="true">
          <svg viewBox="0 0 24 24">
            <path d="M20 6L9 17l-5-5"/>
          </svg>
        </span>
        <div class="nuve-tip-text">{{ t }}</div>
      </div>
    {%- endfor -%}
  </div>
</div>

{%- comment -%}
Nuvé CTA Section (all-in-one)
- Lilac background panel
- Headline + subcopy
- Button (either scroll-to-buy OR real Add to Cart)
- Guarantee line

How to use:
1) Place this section anywhere on the PRODUCT template.
2) Ensure you have <div id="buy"> anchor near your main purchase module if using scroll mode.
3) Set button_mode to 'scroll' or 'atc'
{%- endcomment -%}

{%- assign heading = 'Ready to Upgrade Your Hair Routine?' -%}
{%- assign subtext = 'Start your at-home routine for thicker, healthier-looking hair — no clinic visits required.' -%}
{%- assign button_text = 'Get Nuvé Stamp Now' -%}
{%- assign guarantee_text = '30-Day Money-Back Guarantee' -%}

{%- comment -%}
button_mode:
- 'scroll' = button links to #buy
- 'atc' = button adds to cart (product page only)
{%- endcomment -%}
{%- assign button_mode = 'scroll' -%}

{%- style -%}
  .nuve-cta-section{
    --ink:#0f172a;
    --muted:rgba(15,23,42,.72);
    --lilac:#d9cffc; /* close to screenshot */
    --lilac-2:#c9b7ff;
    --shadow: 0 18px 55px rgba(15,23,42,.10);

    max-width: 1100px;
    margin: 0 auto;
    padding: 28px 18px;
  }

  .nuve-cta-panel{
    background: var(--lilac);
    border-radius: 22px;
    padding: 42px 22px;
    text-align: center;
    box-shadow: var(--shadow);
    border: 1px solid rgba(15,23,42,.08);
    position: relative;
    overflow: hidden;
  }

  /* subtle glow accents */
  .nuve-cta-panel:before{
    content:"";
    position:absolute;
    inset:-200px -200px auto auto;
    width: 420px;
    height: 420px;
    background: radial-gradient(circle, rgba(201,183,255,.55), rgba(201,183,255,0) 60%);
    transform: translate(20%, -15%);
    pointer-events:none;
  }
  .nuve-cta-panel:after{
    content:"";
    position:absolute;
    inset:auto auto -220px -220px;
    width: 520px;
    height: 520px;
    background: radial-gradient(circle, rgba(255,255,255,.45), rgba(255,255,255,0) 60%);
    pointer-events:none;
  }

  .nuve-cta-inner{
    position: relative;
    z-index: 1;
    max-width: 860px;
    margin: 0 auto;
  }

  .nuve-cta-title{
    font-size: 44px;
    font-weight: 900;
    letter-spacing: -0.03em;
    color: #0b0f1a;
    margin: 0 0 14px;
    line-height: 1.05;
  }

  .nuve-cta-sub{
    font-size: 16px;
    font-weight: 600;
    color: rgba(11,15,26,.78);
    margin: 0 auto 22px;
    line-height: 1.55;
    max-width: 720px;
  }

  .nuve-cta-btn{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    padding: 16px 28px;
    border-radius: 9999px;
    background: #0b0b0c;
    color: #fff;
    font-size: 15px;
    font-weight: 900;
    text-decoration: none;
    border: 0;
    cursor: pointer;
    box-shadow: 0 14px 34px rgba(0,0,0,.22);
    transition: transform .14s ease, box-shadow .14s ease, opacity .14s ease;
    min-width: 260px;
  }
  .nuve-cta-btn:hover{ transform: translateY(-1px); box-shadow: 0 18px 42px rgba(0,0,0,.26); }
  .nuve-cta-btn:active{ transform: translateY(0); opacity:.92; }
  .nuve-cta-btn[disabled]{ opacity:.6; cursor:not-allowed; transform:none; box-shadow:none; }

  .nuve-cta-guarantee{
  margin-top: 16px;
  display: flex;            /* <- key change */
  justify-content: center;  /* center it */
  align-items: center;
  gap: 10px;
  width: 100%;              /* forces it onto its own line */
  font-size: 13px;
  font-weight: 700;
  color: rgba(11,15,26,.78);
}

  .nuve-cta-ico{
    width: 18px;
    height: 18px;
    display:inline-block;
  }
  .nuve-cta-ico svg{
    width: 100%;
    height: 100%;
    display:block;
    stroke: rgba(11,15,26,.78);
    fill:none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  /* Responsive */
  @media (max-width: 749px){
    .nuve-cta-panel{ padding: 34px 18px; }
    .nuve-cta-title{ font-size: 34px; }
    .nuve-cta-sub{ font-size: 15px; }
    .nuve-cta-btn{ min-width: 220px; }
  }
{%- endstyle -%}

<section class="nuve-cta-section">
  <div class="nuve-cta-panel">
    <div class="nuve-cta-inner">
      <h2 class="nuve-cta-title">{{ heading }}</h2>
      <p class="nuve-cta-sub">{{ subtext }}</p>

      {%- if button_mode == 'scroll' -%}
        <a class="nuve-cta-btn" href="#buy">{{ button_text }}</a>

      {%- elsif button_mode == 'atc' and product -%}
        {%- assign v = product.selected_or_first_available_variant -%}
        <product-form>
          {% form 'product', product, id: 'nuveInlineCTA', novalidate: 'novalidate' %}
            <input type="hidden" name="id" value="{{ v.id }}">
            <input type="hidden" name="quantity" value="1">
            <button class="nuve-cta-btn" type="submit" name="add" {% unless v.available %}disabled{% endunless %}>
              {% if v.available %}{{ button_text }}{% else %}Sold out{% endif %}
            </button>
          {% endform %}
        </product-form>
      {%- else -%}
        <a class="nuve-cta-btn" href="#buy">{{ button_text }}</a>
      {%- endif -%}

      <div class="nuve-cta-guarantee">
        <span class="nuve-cta-ico" aria-hidden="true">
          <!-- shield check -->
          <svg viewBox="0 0 24 24">
            <path d="M12 2l8 4v6c0 5-3.5 9.4-8 10-4.5-.6-8-5-8-10V6l8-4z"/>
            <path d="M8.5 12.3l2.2 2.2 4.8-5.2"/>
          </svg>
        </span>
        <span>{{ guarantee_text }}</span>
      </div>
    </div>
  </div>
</section>

{%- comment -%}
If you use button_mode = 'scroll', make sure you have this anchor above your buy box:
<div id="buy" style="position: relative; top: -90px;"></div>
{%- endcomment -%}
